class Solution:
    def romanToInt(self, s):
        v = {'I':1,'V':5,'X':10,'L':50,'C':100,'D':500,'M':1000}
        for a, b in [('CM','DCCCC'),('CD','CCCC'),('XC','LXXXX'),('XL','XXXX'),('IX','VIIII'),('IV','IIII')]:
            s = s.replace(a, b)
        return sum(v[ch] for ch in s)

